@app.route('/login', methods=['POST'])
def login(req):
    username = req.form['username']
    password = req.form['password']
    logger.info('auth.login.attempt', extra={
        'event': 'auth.login.attempt',
        'user_id': hash_id(username),
        'request_id': req.request_id,
    })  # password never logged
    return authenticate(username, password)

func sanitize(s string) string {
    r := strings.NewReplacer("\n", "", "\r", "", "\t", " ")
    return r.Replace(s)
}

func handleSearch(w http.ResponseWriter, r *http.Request) {
    query := r.URL.Query().Get("q")
    log.Printf("event=search query=%q", sanitize(query))
    writeJSON(w, search(query))
}

const REDACT = new Set(['authorization', 'cookie', 'set-cookie']);
app.use((req, res, next) => {
  const safeHeaders = Object.fromEntries(
    Object.entries(req.headers).filter(([k]) => !REDACT.has(k.toLowerCase()))
  );
  logger.info({ event: 'http.request', method: req.method, path: req.path, headers: safeHeaders });
  next();
});
